pub fn run(args: Args, root: &Path, format: OutputFormat) -> Result<()> {
    let cache = CacheDir::at(root);
    if args.force {
        // Best-effort: drop any prior payload + meta so neither the strict
        // load nor the stale-load fallback in load_or_build_engine could
        // sneak in if a downstream caller invoked it.
        let _ = std::fs::remove_file(cache.symbol_path());
        let _ = std::fs::remove_file(cache.bigram_path());
        let _ = std::fs::remove_file(cache.meta_path());
    }

    let engine = Engine::default();
    let report = engine.index(root);
    let cache_written = cache
        .write_symbol_index(&engine.handles.symbols, root)
        .is_ok();

    // Build the bigram prefilter from the same set of paths the engine
    // just walked. Reading content twice is unfortunate but keeps the
    // bigram module standalone; for typical repos the second pass is
    // dominated by FS cache hits from the first pass.
    let walk_paths = super::walk_files(root);
    let bigram = GrepBigram::build(&walk_paths);
    let bigram_cache_written = cache.write_bigram_index(&bigram).is_ok();

    let payload = IndexOutput {
        files_visited: report.files_visited,
        files_indexed: report.files_indexed,
        files_skipped_other: report.files_skipped_other,
        symbols_indexed: engine.handles.symbols.symbols_indexed(),
        bigram_files: bigram.file_count(),
        bigram_count: bigram.bigram_count(),
        cache_path: cache.symbol_path().to_string_lossy().to_string(),
        bigram_cache_path: cache.bigram_path().to_string_lossy().to_string(),
        cache_written,
        bigram_cache_written,
        forced: args.force,
    };
    super::emit(format, &payload, |p| {
        let symbol_line = if p.cache_written {
            format!("Cache: {}\n", p.cache_path)
        } else {
            "Cache: write failed\n".to_string()
        };
        let bigram_line = if p.bigram_cache_written {
            format!(
                "Bigram cache: {} ({} bigrams over {} files)\n",
                p.bigram_cache_path, p.bigram_count, p.bigram_files
            )
        } else {
            "Bigram cache: write failed\n".to_string()
        };
        let prefix = if p.forced {
            "Force-rebuilt index. "
        } else {
            ""
        };
        format!(
            "{}Indexed {} files ({} symbols, {} skipped)\n{}{}",
            prefix,
            p.files_indexed,
            p.symbols_indexed,
            p.files_skipped_other,
            symbol_line,
            bigram_line
        )
    })
}

fn run(root: &Path, args: &[&str]) -> (Value, std::time::Duration) {
    let mut cmd = Command::new(binary());
    cmd.args(["--root", root.to_str().unwrap(), "--format", "json"]);
    cmd.args(args);
    let start = std::time::Instant::now();
    let out = cmd.output().expect("spawn ffs");
    let elapsed = start.elapsed();
    assert!(
        out.status.success(),
        "stderr: {}",
        String::from_utf8_lossy(&out.stderr)
    );
    let v: Value = serde_json::from_slice(&out.stdout).expect("parse json");
    (v, elapsed)
}

pub fn run(args: Args, root: &Path, format: OutputFormat) -> Result<()> {
    let root = root.canonicalize().unwrap_or_else(|_| root.to_path_buf());

    let engine = Engine::default();
    engine.index(&root);

    let files = super::walk_files(&root);

    let mut total_files = 0usize;
    let mut code_files = 0usize;
    let mut total_lines = 0usize;
    let mut total_bytes = 0u64;
    let mut lang_buckets: HashMap<Lang, LangBucket> = HashMap::new();
    let mut build_files: Vec<String> = Vec::new();
    let mut entrypoints: Vec<String> = Vec::new();
    let mut fingerprint_input: Vec<(String, u64, SystemTime)> = Vec::new();

    for path in &files {
        let Ok(meta) = std::fs::metadata(path) else {
            continue;
        };
        let size = meta.len();
        total_bytes += size;
        let mtime = meta.modified().unwrap_or(SystemTime::UNIX_EPOCH);
        total_files += 1;

        let rel = path
            .strip_prefix(&root)
            .unwrap_or(path)
            .to_string_lossy()
            .to_string();

        if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
            if is_build_file(name) {
                build_files.push(rel.clone());
            }
            if is_entrypoint(name, &rel) {
                entrypoints.push(rel.clone());
            }
        }

        if let FileType::Code(lang) = detect_file_type(path) {
            code_files += 1;
            let lines = std::fs::read_to_string(path)
                .map(|c| c.lines().count())
                .unwrap_or(0);
            total_lines += lines;
            let bucket = lang_buckets.entry(lang).or_default();
            bucket.files += 1;
            bucket.code_lines += lines;
            bucket.bytes += size;
        }

        fingerprint_input.push((rel, size, mtime));
    }

    let mut languages: Vec<LanguageStat> = lang_buckets
        .into_iter()
        .map(|(lang, b)| LanguageStat {
            lang: format!("{lang:?}"),
            files: b.files,
            code_lines: b.code_lines,
            bytes: b.bytes,
        })
        .collect();
    languages.sort_by(|a, b| b.code_lines.cmp(&a.code_lines).then(a.lang.cmp(&b.lang)));
    languages.truncate(args.top_languages);

    build_files.sort();
    entrypoints.sort();
    entrypoints.truncate(args.top_entrypoints);

    let top_symbols = collect_top_symbols(&engine, args.top_symbols);

    let fingerprint = fingerprint(&fingerprint_input);

    let payload = OverviewOutput {
        root: root.to_string_lossy().to_string(),
        files: total_files,
        code_files,
        code_lines: total_lines,
        bytes: total_bytes,
        fingerprint,
        languages,
        build_files,
        entrypoints,
        top_symbols,
    };
    super::emit(format, &payload, render_text)
}

